VALUES
  ('police-b20a8cf8-moex-00204', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '為拍攝現場遺留之微物跡證，單眼數位相機可透過適當鏡頭改裝而達成提高放大倍率的近距離攝 影效果，下列有關近距離攝影時改裝鏡頭、對焦與影像放大之相關描述，何者最不適當﹖', '["將標準鏡頭倒接比廣角鏡頭倒接可獲致較大的放大倍率", "鏡頭與機身中銜接中間環套（extensiontube），長度越長則放大倍率越大", "鏡頭前外接近攝鏡（close-uplens），近攝鏡號數（diopternumber）越大則放大倍率越大", "鏡頭與機身中銜接中間環套之後，相機即喪失無限遠（ ）的對焦功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00205', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '疑似使用可燃性液體（ignitableliquid）縱火之火災現場經勘察後進行採樣與鑑定，下列關於火場 ∞ 殘跡之採樣、包裝、前處理與分析之描述，何者最不適當﹖', '["以採取疑似縱火點具多孔性之材質為主要待測樣品，並宜採取非起火處之相同材質為比對樣品", "經採取之樣品，可使用乾淨之金屬鐵罐進行包裝，為確保殘跡中可燃性液體含量並應儘量將鐵 罐填滿", "應用靜態頂空吸附法進行樣品前處理時，宜加入內標準品後，再行加熱吸附之動作", "以氣相層析質譜法分析時，可利用參考物質與待測樣品並經相同前處理後，再進行萃取離子層 析圖之比對"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00206', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關現場勘察與物證處理過程中，為顯現各種潛伏痕跡而透過選用適當光源與攝影技術以增強其 對比效果的敘述，下列何者最適當﹖', '["為顯現深色衣物上遺留之精液斑，在藍綠光照射下進行發光式紅外光攝影", "為顯現深色衣物經輪胎壓印後之胎痕，在紫外光照射下進行發光式紫外光攝影", "為顯現深色衣物經近距離槍擊後射入口周圍之火藥煙暈，在紅外光照射下進行反射式紅外光攝影", "為顯現皮膚下之瘀傷位置，在藍綠光照射下進行發光式紅外光攝影"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00207', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '對於車禍現場所採取之問題汽車油漆與已知油漆之鑑定問題，為進行油漆中接合劑樹脂（binder', '["熱解氣相層析質譜法（Py-GC/MS）", "掃 描式電子顯微鏡/X射線能譜分析法（SEM/EDX）", "顯微分光光譜法（MSP）", "顯微紅外光 譜法（Micro-FTIR）  ⑤偏光顯微鏡法（PLM）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
