  ('police-b20a8cf8-moex-00211', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依據警察偵查犯罪手冊，刑案分為重大刑案、特殊刑案及普通刑案。下列案件何者非屬重大刑案？', '["失竊物總值新臺幣50萬元之竊盜案件", "查獲第一級毒品200公克以上案件", "重傷害或傷害致死案件", "被害人為具外交身分之外籍人員之竊盜案件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00212', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關司法警察受理報案應注意事項，下列何者正確？', '["受理報案態度應誠懇和藹，如為他轄案件，應婉轉說明不予受理原因，請其前往正確管轄機關", "為執法有據，受理報案僅能以書面受理告訴、告發，並詳予記錄後報告長官", "民眾告發案件只需申告犯罪事實，不需知悉犯罪嫌疑人，亦不需請求處罰犯罪嫌疑人", "告訴乃論案件，對於共犯之一人告訴或撤回告訴者，其效力不及於其他共犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00213', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依據新修正之少年事件處理法，下列何者非屬該法第3條所列之曝險行為？', '["加暴行於人或互相鬥毆未至傷害", "無正當理由經常攜帶危險器械", "有預備犯罪或犯罪未遂而為法所不罰之行為", "有施用毒品或迷幻物品之行為而尚未觸犯刑罰法律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
